ide-warning-soft);\n}\n\n.artifact-tree-box {\n  border-color: var(--ide-info-text);\n  background: var(--ide-info-soft);\n}\n\n.update-preview-box {\n  display: flex;\n  flex-direction: column;\n  gap: 8px;\n  padding: 10px;\n  border: 1px solid var(--ide-success-border);\n  border-radius: 10px;\n  background: color-mix(in srgb, var(--ide-bg2) 72%, transparent);\n}\n\n.update-preview-head,\n.update-question-list,\n.plan-history-row {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n}\n\n.update-preview-head {\n  justify-content: space-between;\n}\n\n.update-preview-head strong,\n.update-question-list strong,\n.plan-history-row strong {\n  color: var(--ide-text);\n  font-size: 12px;\n}\n\n.update-preview-head span,\n.plan-history-row span {\n  color: var(--ide-dim-2);\n  font-size: 11px;\n}\n\n.update-impact-list {\n  display: flex;\n  flex-direction: column;\n  gap: 4px;\n  margin: 0;\n  padding-left: 18px;\n  color: var(--ide-text);\n  font-size: 12px;\n  line-height: 1.5;\n}\n\n.update-question-list {\n  align-items: flex-start;\n  color: var(--ide-dim-2);\n  font-size: 12px;\n  line-height: 1.5;\n}\n\n.plan-history-box {\n  border-style: dashed;\n}\n\n.plan-history-list {\n  display: flex;\n  flex-direction: column;\n  gap: 6px;\n}\n\n.plan-history-row {\n  align-items: flex-start;\n  justify-content: space-between;\n  padding: 6px 8px;\n  border-radius: 8px;\n  background: var(--ide-bg);\n}\n\n.todo-list {\n  display: flex;\n  flex-direction: column;\n  gap: 8px;\n}\n\n.todo-row {\n  padding: 8px;\n  border-radius: 10px;\n  background: var(--ide-bg);\n  align-items: flex-start;\n}\n\n.todo-main {\n  flex: 1;\n  min-width: 0;\n  display: flex;\n  flex-direction: column;\n  gap: 3px;\n}\n\n.todo-main strong {\n  color: var(--ide-text);\n  font-size: 12px;\n}\n\n.todo-controls {\n  display: flex;\n  align-items: center;\n  gap: 6px;\n}\n\n.todo-controls select {\n  max-width: 78px;\n  border: 1px solid var(--ide-border);\n  border-radius: 8px;\n  background